previewCss:
.darma-loader-skeleton-avatar {
  display: grid;
  grid-template-columns: 42px 108px;
  gap: 8px 12px;
  align-items: center;
}
.darma-loader-skeleton-avatar b,
.darma-loader-skeleton-avatar i {
  display: block;
  background: linear-gradient(90deg, rgba(99,102,241,.12), rgba(99,102,241,.32), rgba(99,102,241,.12));
  background-size: 220% 100%;
  animation: darma-loader-skeleton-avatar-shimmer 1s linear infinite;
}
.darma-loader-skeleton-avatar b {
  grid-row: span 2;
  width: 42px;
  height: 42px;
  border-radius: 50%;
}
.darma-loader-skeleton-avatar i {
  height: 11px;
  border-radius: 999px;
}
.darma-loader-skeleton-avatar i:last-child { width: 72%; }
@keyframes darma-loader-skeleton-avatar-shimmer { to { background-position: -220% 0; } }

